#include <stdio.h>

int josephus(int n, int k) {
    int res = 0; // 0‑based index
    for (int i = 2; i <= n; ++i) {
        res = (res + k) % i;
    }
    return res + 1; // convert to 1‑based
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        printf("%d\n", josephus(N, K));
    }
    return 0;
}

